11: )
12: 
13: // GraphTransformer is the interface that transformers implement. This
14: // interface is only for transforms that need entire graph visibility.
15: type GraphTransformer interface {
16: 	Transform(*Graph) error
17: }
18: 
19: // GraphVertexTransformer is an interface that transforms a single
20: // Vertex within with graph. This is a specialization of GraphTransformer
21: // that makes it easy to do vertex replacement.
22: //
23: // The GraphTransformer that runs through the GraphVertexTransformers is
24: // VertexTransformer.
25: type GraphVertexTransformer interface {
26: 	Transform(dag.Vertex) (dag.Vertex, error)
27: }
28: 
29: type graphTransformerMulti struct {
30: 	Transforms []GraphTransformer
31: }
32: 
33: func (t *graphTransformerMulti) Transform(g *Graph) error {
34: 	var lastStepStr string
35: 	for _, t := range t.Transforms {
36: 		log.Printf("[TRACE] (graphTransformerMulti) Executing graph transform %T", t)
37: 		if err := t.Transform(g); err != nil {
38: 			return err
39: 		}
40: 		if thisStepStr := g.StringWithNodeTypes(); thisStepStr != lastStepStr {
41: 			log.Printf("[TRACE] (graphTransformerMulti) Completed graph transform %T with new graph:\n%s  ------", t, logging.Indent(thisStepStr))
42: 			lastStepStr = thisStepStr
43: 		} else {
44: 			log.Printf("[TRACE] (graphTransformerMulti) Completed graph transform %T (no changes)", t)
45: 		}
46: 	}
47: 
48: 	return nil
49: }
50: 
51: // GraphTransformMulti combines multiple graph transformers into a single
52: // GraphTransformer that runs all the individual graph transformers.
53: func GraphTransformMulti(ts ...GraphTransformer) GraphTransformer {
54: 	return &graphTransformerMulti{Transforms: ts}
55: }
